import torch
import torch.nn as nn
import numpy as np


class SocialNavPolicy(nn.Module):
    def __init__(self):
        super().__init__()
        self.dummy = nn.Parameter(torch.zeros(1))

    def reset(self):
        pass

    def forward(self, obs, env=None):
        gps = obs["agent_0_goal_to_agent_gps_compass"]
        if isinstance(gps, np.ndarray):
            gps = torch.from_numpy(gps).float()
        else:
            gps = gps.float()
        dist = float(gps[0])
        angle = float(gps[1])

        # --- Pathfinder branch for long-range / wall avoidance ---
        if env is not None and dist > 3.5:
            try:
                import habitat_sim
                import math

                pf = env.sim.pathfinder
                mgr = env.sim.agents_mgr
                robot_pos = np.array(
                    mgr[0].articulated_agent.base_pos, dtype=np.float64
                )
                human_pos = np.array(
                    mgr[1].articulated_agent.base_pos, dtype=np.float64
                )
                r_snap = pf.snap_point(robot_pos)
                h_snap = pf.snap_point(human_pos)

                path = habitat_sim.ShortestPath()
                path.requested_start = r_snap
                path.requested_end = h_snap
                found = pf.find_path(path)

                if found and len(path.points) >= 2:
                    geo = float(path.geodesic_distance)
                    euc = float(np.linalg.norm(np.array(h_snap) - np.array(r_snap)))

                    if geo > euc + 0.5 or dist > 6.0:
                        idx = min(2, len(path.points) - 1)
                        wp = np.array(path.points[idx], dtype=np.float64)

                        bh = math.atan2(
                            float(h_snap[2] - r_snap[2]),
                            float(h_snap[0] - r_snap[0]),
                        )
                        bw = math.atan2(
                            float(wp[2] - r_snap[2]),
                            float(wp[0] - r_snap[0]),
                        )
                        la = angle + (bw - bh)
                        la = (la + math.pi) % (2.0 * math.pi) - math.pi

                        turn = float(np.clip(-5.0 * la, -1.0, 1.0))

                        if abs(la) > 1.0:
                            forward = 0.2
                        elif abs(la) > 0.5:
                            forward = 0.35
                        else:
                            forward = 0.5 if dist < 5.0 else 0.7

                        return torch.tensor([forward, turn], dtype=torch.float32)
            except Exception:
                pass

        # --- Local GPS-based controller with safety margins ---
        turn = float(np.clip(-5.0 * angle, -1.0, 1.0))

        if dist < 1.3:
            forward = -1.0
        elif dist < 1.6:
            forward = -0.3
        elif dist < 2.0:
            forward = 0.4
        elif dist < 2.5:
            forward = 0.7
        elif dist < 4.0:
            forward = 0.85
        else:
            forward = 1.0

        # Angle modulation: reduce forward when not facing target
        if abs(angle) > 1.0:
            forward = 0.1
        elif abs(angle) > 0.5:
            forward = forward * 0.6

        return torch.tensor([forward, turn], dtype=torch.float32)
